    /// <summary>
    /// Resolves the parent <see cref="CountryCode"/> for the supplied
    /// <paramref name="subdivisionCode"/>. Throws
    /// <see cref="InvalidOperationException"/> when the code is not present
    /// in the catalog — fail-loud is intentional (every codegen-issued
    /// SubdivisionCode must be in the table; absence is a bug, not a
    /// user-input case).
    /// </summary>
    /// <param name="subdivisionCode">The raw subdivision code.</param>
    /// <returns>The owning country.</returns>
    public static CountryCode GetParent(string subdivisionCode)
    {
        if (subdivisionCode is null)
            throw new ArgumentNullException(nameof(subdivisionCode));

        if (!sr_parents.TryGetValue(subdivisionCode, out var country))
        {
            throw new InvalidOperationException(
                $"Subdivision code '{subdivisionCode}' is not present in the geo catalog.");
        }

        return country;
    }
}
